sys_script_include.script:
var MetroFareCalculator = Class.create();
MetroFareCalculator.prototype = {
    initialize: function() {},

    calculateNormalFare: function(sourceStation, destinationStation, passengerCount) {
        var count = parseInt(passengerCount, 10);

        if (!count || count < 1) {
            count = 1;
        }

        var fare = this._getBaseFare(sourceStation, destinationStation);

        return fare * count;
    },

    calculateStudentPassAmount: function(sourceStation, destinationStation, passType) {
        var baseFare = this._getBaseFare(sourceStation, destinationStation);

        if (baseFare <= 0) {
            return 0;
        }

        var discount = this._getStudentDiscount(sourceStation, destinationStation);

        var rideCount = 0;

        if (passType == 'weekly') {
            rideCount = 10;
        } else if (passType == 'monthly') {
            rideCount = 40;
        } else {
            rideCount = 1;
        }

        var total = baseFare * rideCount;
        var discountAmount = total * discount / 100;

        return total - discountAmount;
    },

    _getBaseFare: function(sourceStation, destinationStation) {
    var fare = new GlideRecord('x_1877508_metro_0_metro_fare_matrix');
    fare.addQuery('source_station', sourceStation);
    fare.addQuery('destination_station', destinationStation);
    fare.addQuery('active', true);
    fare.query();

    if (fare.next()) {
        return parseFloat(fare.getValue('base_fare')) || 0;
    }

    return 0;
},
    _getStudentDiscount: function(sourceStation, destinationStation) {
        var fare = new GlideRecord('x_1877508_metro_0_metro_fare_matrix');
        fare.addQuery('source_station', sourceStation);
        fare.addQuery('destination_station', destinationStation);
        fare.addQuery('active', true);
        fare.query();

        if (fare.next()) {
            return parseFloat(fare.getValue('student_discount_percentage')) || 0;
        }

        return 0;
    },

    type: 'MetroFareCalculator'
};
